<?php
/**
 * SEED CARTOGRAPHIE PRIVÉE — charge en 1 clic les 42 GA + l'organigramme
 * (données compilées avec Fabrice depuis Action Populaire). Dédoublonnage
 * intégré : on n'ajoute jamais deux fois le même GA / la même personne.
 * Contacts de GA (non cloisonnés) — jamais de données d'enquête ici.
 */
if (!defined('ABSPATH')) exit;

function lfi_nct_carto_seed_ga_raw() {
    return base64_decode('');
}
function lfi_nct_carto_seed_people_raw() {
    return base64_decode('');
}

/** Parse « a ; b ; c … » (une entité par ligne) → tableau de tableaux de champs. */
function lfi_nct_carto_seed_parse($raw) {
    $out = [];
    foreach (preg_split('/\r\n|\r|\n/', (string) $raw) as $line) {
        $line = trim($line);
        if ($line === '') continue;
        $out[] = array_map('trim', preg_split('/\t|;|\|/', $line));
    }
    return $out;
}

/**
 * Charge GA + organigramme dans les options, en DÉDOUBLONNANT :
 *  - GA par nom ; personnes par (nom + niveau).
 * Renvoie un rapport [ga_add, ga_dup, ppl_add, ppl_dup].
 */
function lfi_nct_carto_seed_load() {
    $rep = ['ga_add' => 0, 'ga_dup' => 0, 'ppl_add' => 0, 'ppl_dup' => 0];

    /* --- GA --- */
    $list = function_exists('lfi_nct_carto_all') ? lfi_nct_carto_all() : [];
    $seen = [];
    foreach ($list as $e) { $k = mb_strtolower(trim((string) ($e['nom'] ?? ''))); if ($k !== '') $seen[$k] = 1; }
    foreach (lfi_nct_carto_seed_parse(lfi_nct_carto_seed_ga_raw()) as $c) {
        $nom = sanitize_text_field($c[0] ?? ''); if ($nom === '') continue;
        $k = mb_strtolower($nom);
        if (isset($seen[$k])) { $rep['ga_dup']++; continue; }
        $seen[$k] = 1;
        $list[] = [
            'id'       => function_exists('lfi_nct_carto_next_id') ? lfi_nct_carto_next_id($list) : (count($list) + 1),
            'nom'      => $nom,
            'commune'  => sanitize_text_field($c[1] ?? ''),
            'email'    => sanitize_email($c[2] ?? ''),
            'contact'  => sanitize_text_field($c[3] ?? ''),
            'tel'      => sanitize_text_field($c[4] ?? ''),
            'contact2' => sanitize_text_field($c[5] ?? ''),
            'email2'   => sanitize_email($c[6] ?? ''),
            'statut'   => 'a_contacter',
            'notes'    => '',
        ];
        $rep['ga_add']++;
    }
    if (function_exists('lfi_nct_carto_save')) lfi_nct_carto_save($list);

    /* --- Organigramme (personnes) --- */
    $people = function_exists('lfi_nct_carto_people_all') ? lfi_nct_carto_people_all() : [];
    $niveaux = function_exists('lfi_nct_carto_niveaux') ? lfi_nct_carto_niveaux() : [];
    $pseen = [];
    foreach ($people as $e) { $pk = mb_strtolower(trim((string) ($e['nom'] ?? '')) . '|' . ($e['niveau'] ?? '')); $pseen[$pk] = 1; }
    foreach (lfi_nct_carto_seed_parse(lfi_nct_carto_seed_people_raw()) as $c) {
        $nom = sanitize_text_field($c[0] ?? ''); if ($nom === '') continue;
        $niv = sanitize_key($c[4] ?? ''); if ($niveaux && !isset($niveaux[$niv])) $niv = 'terrain';
        $pk = mb_strtolower($nom . '|' . $niv);
        if (isset($pseen[$pk])) { $rep['ppl_dup']++; continue; }
        $pseen[$pk] = 1;
        $people[] = [
            'id'         => function_exists('lfi_nct_carto_next_id') ? lfi_nct_carto_next_id($people) : (count($people) + 1),
            'nom'        => $nom,
            'fonction'   => sanitize_text_field($c[1] ?? ''),
            'email'      => sanitize_email($c[2] ?? ''),
            'ap_url'     => esc_url_raw($c[3] ?? ''),
            'niveau'     => $niv,
            'ga_nom'     => sanitize_text_field($c[5] ?? ''),
            'ga_membres' => (int) ($c[6] ?? 0),
        ];
        $rep['ppl_add']++;
    }
    if (function_exists('lfi_nct_carto_people_save')) lfi_nct_carto_people_save($people);

    return $rep;
}
